def label_maps(metadata): return {k:canonical_label(v.get("episode_class") or v.get("label")) for k,v in metadata.items()}
def evaluate_all(records,metadata):
    ordered=canonical_sort(records); labels_by_id=label_maps(metadata); labels=[labels_by_id[r["immutable_row_id"]] for r in ordered]
    window=evaluate_window(labels,ordered); episode,_=evaluate_episode(ordered,metadata); state=evaluate_stateful(labels_by_id,ordered,episode)
    window.update({"stateful":state,"episode":episode})
    runs={}
    for run in sorted({r["run_id"] for r in ordered}):
        subset=[r for r in ordered if r["run_id"]==run]; labs=[labels_by_id[r["immutable_row_id"]] for r in subset]; runs[run]=evaluate_window(labs,subset)
        run_episode,_=evaluate_episode(subset,metadata)
        episode["per_run"][run].update({k:run_episode[k] for k in ("episode_alert_precision","benign_episode_false_alert_rate","unresolved_pending_episode_rate")})
    window["per_run"]=runs; window["per_group_episode"]=episode["per_group"]; window["per_length_episode"]=episode["per_episode_length"]; return window
def legacy_physical(records,metadata):
    groups={}
    for r in records:
        m=metadata[r["immutable_row_id"]]; label=canonical_label(m.get("episode_class") or m.get("label"))
        if label=="benign": continue
        groups.setdefault((r["run_id"],str(m["episode_id"])),[]).append(r)
    alerts=[next((i+1 for i,r in enumerate(rows) if r["primary_state"].startswith("alert_emitted:")),None) for rows in groups.values()]; n=len(alerts)
    return {"attack_episode_count":n,"alert_counts":{str(i):sum(x==i for x in alerts) for i in range(1,4)},"detection_by_first":sum(x and x<=1 for x in alerts)/n,"detection_by_second":sum(x and x<=2 for x in alerts)/n,"detection_by_third":sum(x and x<=3 for x in alerts)/n}
def bootstrap(metrics_by_run,episode_by_run,iterations=5000,seed=42):
    rng=np.random.default_rng(seed); runs=list(metrics_by_run); keys=("macro_f1","benign_recall","FPR","attack_macro_recall"); episode_keys=("attack_episode_recall","episode_alert_precision","benign_episode_false_alert_rate","detection_by_second_window","unresolved_pending_episode_rate")
    values={k:[] for k in keys+episode_keys}
    for _ in range(iterations):
        sample=rng.choice(runs,len(runs),replace=True)
        for k in keys: values[k].append(float(np.mean([metrics_by_run[r][k] for r in sample])))
        for k in episode_keys: values[k].append(float(np.mean([episode_by_run[r][k] for r in sample])))
    return {"iterations":iterations,"seed":seed,"unit":"run_id","intervals":{k:{"low":float(np.quantile(v,.025)),"high":float(np.quantile(v,.975))} for k,v in values.items()}}
